def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            threshold = j * 0.1
            if ratio < threshold:
                score += (11 - j) * np.log(1 + capacity) * np.sqrt(item + j)
            else:
                penalty = j * np.sqrt(item) / (np.log(1 + capacity) + 1)
                if j % 2 == 0:
                    score -= penalty * 1.2
                else:
                    score -= penalty * 0.8
        if capacity < item * 1.2:
            score *= 2
            for k in range(3):
                score -= np.exp(-k) * np.sqrt(item)
        elif capacity > item * 4:
            score /= 3
            for k in range(1, 4):
                if capacity / k > item:
                    score += np.log(capacity / (item * k))
                else:
                    score -= np.sqrt(item * k)
        else:
            for m in range(5):
                if (capacity - item * (m + 1)) > 0:
                    score += np.log1p(capacity - item * (m + 1)) / (m + 1)
                else:
                    score -= (m + 1) * np.sqrt(item)
        if np.isnan(score) or np.isinf(score):
            priorities[i] = -np.inf
        else:
            priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 20
    return priorities
